#include<bits/stdc++.h>
using namespace std;
char a[4100];
int n;
string s;
void dfs(int x,string aa){

    string b="",c="";
        bool flag1=1,flag2=1;
        for(int i=0;i<aa.size();i++){
            if(i<(aa.size()/2)){
                b+=aa[i];
            }else{
                c+=aa[i];
            }
            if(aa[i]=='0'){
                flag1=0;
            }else{
                flag2=0;
            }
        }
        if(flag2==0&&flag1==1){
            a[x]='I';
        }else if(flag2==1&&flag1==0){
            a[x]='B';
        }else{
            a[x]='F';
        }
    if(aa.size()>1){
        dfs(x*2,b);
        dfs(x*2+1,c);
    }
    else{
        a[x*2]='.';
        a[x*2+1]='.';
        return;
    }
}
void hou(int x){
    if(a[x]=='.'){
        return;
    }else{
        hou(x*2);
        hou(x*2+1);
        cout<<a[x];
    }
}
int main(){

    cin>>n;
    //cout<<1<<"\n";
    cin>>s;
    //cout<<1<<"\n";
    dfs(1,s);
    hou(1);
    return 0;
}
